// Split the media data array into individual items
const posts = $json.data || [];

if (posts.length === 0) {
  console.log('No posts found in the past 7 days.');
  return [];
}

console.log(`Found ${posts.length} posts to process`);
return posts.map(post => ({ json: post }));

// Determine which metrics to fetch based on media type
const post = $json;
const isReel = post.media_type === 'VIDEO' || post.media_type === 'REELS';
const isCarousel = post.media_type === 'CAROUSEL_ALBUM';

const metricsToFetch = isReel
  ? 'reach,impressions,saved,shares,video_views,total_interactions,follows,profile_visits,ig_reels_avg_percentage_watched'
  : 'reach,impressions,saved,shares,total_interactions,follows,profile_visits';

return [{ json: { ...post, _metricsToFetch: metricsToFetch, _isReel: isReel, _isCarousel: isCarousel } }];

// Merge insights response with original post data
// $json = insight API response
// $('Set Metrics String').item.json = original post data for this item
const insightData = $json.data || [];
const post = $('Set Metrics String').item.json;

// Build flat insights map
const insightMap = {};
for (const metric of insightData) {
  const val = metric.values?.[0]?.value ?? metric.value ?? 0;
  insightMap[metric.name] = val;
}

// Extract hook (first non-empty line of caption)
const caption = post.caption || '';
const hook = caption.split('\n').map(l => l.trim()).filter(l => l.length > 0)[0] || '';

// Detect ManyChat CTA keyword
const MANYCHAT_KEYWORDS = ['KNEE', 'FREE', 'ELBOW', 'SHOULDER', 'RECOVERY', 'DROP'];
const upperCaption = caption.toUpperCase();
let ctaKeyword = '';
for (const kw of MANYCHAT_KEYWORDS) {
  if (new RegExp('\\b' + kw + '\\b').test(upperCaption)) { ctaKeyword = kw; break; }
}

// Classify content pillar
const lower = caption.toLowerCase();
let pillar = 'Unclassified';
if (['knee', 'elbow', 'shoulder', 'pain', 'injury', 'hurt', 'inflammation', 'tendon'].some(k => lower.includes(k))) {
  pillar = 'Pain & Injury';
} else if (['third shot', 'reset', 'kitchen', 'movement', 'drop', 'technique', 'drill', 'dink', 'footwork'].some(k => lower.includes(k))) {
  pillar = 'Performance & Technique';
} else if (['recovery', 'longevity', 'rest', 'sleep', 'mobility', 'maintenance', 'over 50', 'over 40', 'stretch'].some(k => lower.includes(k))) {
  pillar = 'Recovery & Longevity';
} else if (['chiropractor', 'dupr', ' dc ', 'doctor', 'background', 'story', 'why i', 'case', 'chiro', 'adjustment', 'licensed'].some(k => lower.includes(k))) {
  pillar = 'Credibility & Story';
}

// Normalize completion rate
let completionRate = null;
if (post._isReel && insightMap.ig_reels_avg_percentage_watched != null) {
  const raw = insightMap.ig_reels_avg_percentage_watched;
  completionRate = raw > 1 ? Math.round(raw) : Math.round(raw * 100);
}

// Day of week
const DAYS = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const postDate = new Date(post.timestamp);
const mediaType = post._isReel ? 'Reel' : post._isCarousel ? 'Carousel' : 'Image';

return [{
  json: {
    id: post.id,
    timestamp: post.timestamp,
    postDate: postDate.toLocaleDateString('en-US', {month:'2-digit', day:'2-digit', year:'numeric'}),
    dayOfWeek: DAYS[postDate.getDay()],
    mediaType,
    caption,
    hook,
    ctaKeyword,
    pillar,
    reach: insightMap.reach || 0,
    impressions: insightMap.impressions || 0,
    videoViews: insightMap.video_views || 0,
    completionRate,
    saves: insightMap.saved || 0,
    shares: insightMap.shares || 0,
    comments: post.comments_count || 0,
    likes: post.like_count || 0,
    profileVisits: insightMap.profile_visits || 0,
    follows: insightMap.follows || 0,
  }
}];

// Grade all posts and build the weekly summary
const posts = $json.allPosts || [];
const weekOf = $('Set Variables').first().json.WEEK_OF;

if (posts.length === 0) return [{ json: { gradedPosts: [], summary: {}, promptData: 'No posts this week.', weekOf } }];

function clamp(val, min, max) { return Math.max(min, Math.min(max, val)); }

// Account averages (baseline for scoring)
const avgReach = posts.reduce((s, p) => s + (p.reach || 0), 0) / posts.length || 1;
const avgProfileVisits = posts.reduce((s, p) => s + (p.profileVisits || 0), 0) / posts.length || 1;

function gradePost(post) {
  const isReel = post.mediaType === 'Reel';

  // Reach score (25pts): 2x avg = 25, 1x avg = 12, linear scale
  const reachRatio = post.reach / avgReach;
  let reachScore;
  if (reachRatio >= 2) reachScore = 25;
  else if (reachRatio >= 1) reachScore = Math.round(12 + (reachRatio - 1) * 13);
  else reachScore = Math.round(reachRatio * 12);

  // Completion score (25pts, Reels only)
  let completionScore = null;
  if (isReel && post.completionRate != null) {
    if (post.completionRate >= 70) completionScore = 25;
    else if (post.completionRate >= 50) completionScore = 18;
    else if (post.completionRate >= 30) completionScore = 10;
    else completionScore = 0;
  }

  // Saves score (20pts): target = 5% of reach
  const savesRate = post.reach > 0 ? post.saves / post.reach : 0;
  const savesScore = Math.round(clamp((savesRate / 0.05) * 20, 0, 20));

  // Shares score (20pts)
  let sharesScore;
  if (post.shares >= 10) sharesScore = 20;
  else if (post.shares >= 5) sharesScore = 14;
  else if (post.shares >= 1) sharesScore = 8;
  else sharesScore = 0;

  // Profile visits score (10pts): scale vs avg
  const pvRatio = post.profileVisits / avgProfileVisits;
  const pvScore = Math.round(clamp(pvRatio >= 2 ? 10 : pvRatio * 5, 0, 10));

  let total;
  if (isReel && completionScore !== null) {
    total = reachScore + completionScore + savesScore + sharesScore + pvScore;
  } else {
    // Redistribute completion weight proportionally for non-reels
    const scaledReach = Math.round(reachScore * 2);
    const scaledSaves = Math.round(savesScore * 1.25);
    const scaledShares = Math.round(sharesScore * 1.25);
    total = scaledReach + scaledSaves + scaledShares + pvScore;
  }

  const score = clamp(Math.round(total), 0, 100);

  let gradeLabel, gradeColor;
  if (score >= 80) { gradeLabel = '🟢 DOUBLE DOWN'; gradeColor = '#34A853'; }
  else if (score >= 55) { gradeLabel = '🟡 MODIFY'; gradeColor = '#FFC000'; }
  else if (score >= 30) { gradeLabel = '🔴 RETIRE'; gradeColor = '#EA4335'; }
  else { gradeLabel = '⚫ KILL IT'; gradeColor = '#434343'; }

  return { ...post, performanceScore: score, gradeLabel, gradeColor };
}

const gradedPosts = posts.map(gradePost);
const sorted = [...gradedPosts].sort((a, b) => b.performanceScore - a.performanceScore);
const top3 = sorted.slice(0, 3);
const worst = sorted[sorted.length - 1];

// Pillar analysis
const pillarMap = {};
for (const p of gradedPosts) {
  if (!pillarMap[p.pillar]) pillarMap[p.pillar] = { total: 0, count: 0 };
  pillarMap[p.pillar].total += p.performanceScore;
  pillarMap[p.pillar].count++;
}
let bestPillar = 'N/A', bestPillarAvg = 0;
for (const [pillar, { total, count }] of Object.entries(pillarMap)) {
  const avg = total / count;
  if (avg > bestPillarAvg) { bestPillarAvg = avg; bestPillar = pillar; }
}

// CTA keyword usage
const ctaUsage = {};
for (const p of gradedPosts) {
  if (p.ctaKeyword) ctaUsage[p.ctaKeyword] = (ctaUsage[p.ctaKeyword] || 0) + 1;
}

// Hook pattern analysis
const topHooks = top3.map(p => p.hook);
const hookPatterns = [];
if (topHooks.some(h => h.includes('?'))) hookPatterns.push('Question hook');
if (topHooks.some(h => /\d/.test(h))) hookPatterns.push('Number/stat hook');
if (topHooks.some(h => /\byou\b/i.test(h))) hookPatterns.push('Direct you-callout');
if (topHooks.some(h => /\bif\b/i.test(h))) hookPatterns.push('Conditional if-hook');
if (!hookPatterns.length) hookPatterns.push('Mixed patterns');

// Averages
const reelPosts = gradedPosts.filter(p => p.mediaType === 'Reel' && p.completionRate != null);
const avgReachFinal = Math.round(gradedPosts.reduce((s, p) => s + p.reach, 0) / gradedPosts.length);
const avgCompletion = reelPosts.length
  ? Math.round(reelPosts.reduce((s, p) => s + (p.completionRate || 0), 0) / reelPosts.length)
  : null;

// Format prompt for Claude
const postsBlock = sorted.map(p =>
  `[${p.gradeLabel}] Score: ${p.performanceScore}/100\n  Hook: "${p.hook}"\n  Type: ${p.mediaType} | Pillar: ${p.pillar} | Day: ${p.dayOfWeek}\n  Reach: ${p.reach} | Completion: ${p.completionRate != null ? p.completionRate + '%' : 'N/A'} | Saves: ${p.saves} | Shares: ${p.shares} | Profile Visits: ${p.profileVisits}${p.ctaKeyword ? '\n  CTA Keyword: ' + p.ctaKeyword : ''}`
).join('\n\n');

const ctaLine = Object.keys(ctaUsage).length
  ? Object.entries(ctaUsage).map(([k, v]) => `${k}: ${v}x`).join(', ')
  : 'None used';

const promptData = `Week of ${weekOf} — ${gradedPosts.length} posts analyzed\nAvg Reach: ${avgReachFinal} | Avg Completion Rate (Reels): ${avgCompletion != null ? avgCompletion + '%' : 'N/A'}\nBest Performing Pillar: ${bestPillar} (avg score: ${Math.round(bestPillarAvg)})\nCTA Keywords Used: ${ctaLine}\nTop Hook Patterns: ${hookPatterns.join(' | ')}\n\n=== ALL POSTS (sorted by score, high to low) ===\n\n${postsBlock}`;

const summary = {
  weekOf,
  totalPosts: gradedPosts.length,
  avgReach: avgReachFinal,
  avgCompletionRate: avgCompletion != null ? avgCompletion + '%' : 'N/A',
  bestPillar: bestPillar + ' (avg score: ' + Math.round(bestPillarAvg) + ')',
  top1: top3[0] ? `${top3[0].gradeLabel} | Score: ${top3[0].performanceScore} | "${top3[0].hook}"` : '',
  top2: top3[1] ? `${top3[1].gradeLabel} | Score: ${top3[1].performanceScore} | "${top3[1].hook}"` : '',
  top3: top3[2] ? `${top3[2].gradeLabel} | Score: ${top3[2].performanceScore} | "${top3[2].hook}"` : '',
  worstPost: worst ? `${worst.gradeLabel} | Score: ${worst.performanceScore} | "${worst.hook}"` : '',
  ctaKeywordsUsed: ctaLine,
  hookPatterns: hookPatterns.join(' | '),
};

return [{ json: { gradedPosts, summary, promptData, weekOf } }];

// Format the weekly summary as a flat row for Google Sheets
const s = $json.summary;
return [{ json: {
  'Week Of': s.weekOf,
  'Total Posts': s.totalPosts,
  'Avg Reach': s.avgReach,
  'Avg Completion Rate': s.avgCompletionRate,
  'Best Pillar': s.bestPillar,
  'Top Post 1': s.top1,
  'Top Post 2': s.top2,
  'Top Post 3': s.top3,
  'Worst Post': s.worstPost,
  'CTA Keywords Used': s.ctaKeywordsUsed,
  'Hook Patterns': s.hookPatterns,
}}];

// Extract report text from Claude response
const reportText = $json.content?.[0]?.text || 'Report generation failed — check API key and quota.';
const weekOf = $('Format Claude Prompt').first().json._weekOf;

console.log(`AI Report generated — ${reportText.length} characters`);

return [{ json: {
  'Week Of': weekOf,
  'AI Strategy Report': reportText,
  _reportText: reportText,
}}];

// Log error details
const err = $json;
console.error('AUDIT PIPELINE ERROR:', JSON.stringify(err, null, 2));

// Extract useful error info
const errorMsg = err.error?.message || err.message || 'Unknown error';
const failedNode = err.execution?.lastNodeExecuted || 'Unknown node';
const workflowName = err.workflow?.name || 'Pickleball Chiro Audit';

console.log(`Workflow: ${workflowName}`);
console.log(`Failed at: ${failedNode}`);
console.log(`Error: ${errorMsg}`);

if (errorMsg.toLowerCase().includes('token') || errorMsg.toLowerCase().includes('oauth') || errorMsg.toLowerCase().includes('session')) {
  console.log('ACTION REQUIRED: Instagram access token may be expired. Follow Step B4 in SETUP-GUIDE.md to refresh.');
}

return [{ json: { errorLogged: true, failedNode, errorMsg } }];
